<span class="line"><span style="color:#CBA6F7;">            let</span><span style="color:#CDD6F4;"> _ </span><span style="color:#94E2D5;">=</span><span style="color:#F38BA8;"> self</span><span style="color:#94E2D5;">.</span><span style="color:#CDD6F4;">pending</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">split_to</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">start</span><span style="color:#9399B2;">);</span></span>
